function search_for_primes(start, times) {
    return times === 0
           ? true
           : start > 2 && start % 2 === 0
           ? search_for_primes(start + 1, times)
           // if we get true, it's a prime
           : timed_prime_test(start)
           ? search_for_primes(start + 2, times - 1)
           : search_for_primes(start + 2, times);
}
